JS=r'''
/* Calendar timeline v1 start */
const TL0=6,TL1=22,TLS=30,TLD=60,TLP=1.1;
function tm(v){if(!v)return null;let a=String(v).slice(0,5).split(':').map(Number);return Number.isFinite(a[0])?a[0]*60+a[1]:null}function mt(n){n=Math.max(0,Math.min(1439,Math.round(n)));return pad(Math.floor(n/60))+':'+pad(n%60)}function dur(t){let a=tm(t.start_time),b=tm(t.end_time);return a!=null&&b!=null&&b>a?b-a:Number(t.duration_minutes)>0?Number(t.duration_minutes):TLD}
function ensureTaskCalendarUi(){if($('taskStartTime'))return;let due=$('taskDue'),g=due&&due.closest?due.closest('.form-grid'):null;if(!due||!g)return;let w=document.createElement('div');w.className='full task-calendar-box';w.innerHTML='<label class="task-calendar-head"><input id="taskAllDay" type="checkbox"> <span>Весь день / без конкретного времени</span></label><div class="task-calendar-time-grid"><label><span>Время начала</span><input class="input" id="taskStartTime" type="time"></label><label><span>Время окончания</span><input class="input" id="taskEndTime" type="time"></label><label><span>Длительность, мин</span><input class="input" id="taskDurationMinutes" type="number" min="1" step="5" placeholder="60"></label></div>';let l=due.closest('label');l&&l.parentNode?l.parentNode.insertBefore(w,l.nextSibling):g.appendChild(w)}
function syncTaskCalendarUi(){ensureTaskCalendarUi();let a=!!$('taskAllDay')?.checked;['taskStartTime','taskEndTime','taskDurationMinutes'].forEach(id=>{let e=$(id);if(e)e.disabled=a})}
function readTaskCalendarFields(){ensureTaskCalendarUi();let all=!!$('taskAllDay')?.checked,st=$('taskStartTime')?.value||null,en=$('taskEndTime')?.value||null,dr=$('taskDurationMinutes')?.value||'',du=dr?Number(dr):null;if(all)return{is_all_day:true,start_time:null,end_time:null,duration_minutes:null};if(en&&!st)throw Error('Укажите время начала');if(st&&en&&en<=st)throw Error('Время окончания должно быть позже времени начала');if(du!=null&&(!Number.isFinite(du)||du<=0))throw Error('Длительность должна быть больше 0');return{is_all_day:false,start_time:st,end_time:en,duration_minutes:du}}
function fillTaskCalendarFields(t){ensureTaskCalendarUi();if($('taskStartTime'))$('taskStartTime').value=t?.start_time?String(t.start_time).slice(0,5):'';if($('taskEndTime'))$('taskEndTime').value=t?.end_time?String(t.end_time).slice(0,5):'';if($('taskDurationMinutes'))$('taskDurationMinutes').value=t?.duration_minutes||'';if($('taskAllDay'))$('taskAllDay').checked=!!t?.is_all_day;syncTaskCalendarUi()}
function wstart(v){let d=D(v||today()),w=d.getDay()||7;d.setDate(d.getDate()-w+1);return ymd(d)}function inDay(t,d){let a=t.start_date||t.due_date||t.recurrence_date,b=t.due_date||t.start_date||t.recurrence_date;return !!(a||b)&&a<=d&&d<=b}
function tf(){return{q:($('tlQ')?.value||'').toLowerCase(),p:$('tlP')?.value||'all',u:$('tlU')?.value||'all',s:$('tlS')?.value||'all',r:$('tlR')?.value||'all',done:!!$('tlDone')?.checked}}
function passT(t,f){if(t.deleted_at)return false;if(!f.done&&t.status==='done')return false;if(f.p!='all'&&t.project_id!==f.p)return false;if(f.s!='all'&&t.status!==f.s)return false;if(f.r!='all'&&t.priority!==f.r)return false;if(f.u!='all'&&!tids(t).includes(f.u))return false;if(f.q&&!([t.title,t.notes,pname(t.project_id),...tids(t).map(uname)].join(' ').toLowerCase().includes(f.q)))return false;return true}
function tt(t){let x=t.start_time?String(t.start_time).slice(0,5)+(t.end_time?'–'+String(t.end_time).slice(0,5):''):'';return (x?'<b>'+esc(x)+'</b> ':'')+(t.is_favorite?'★ ':'')+(t.recurrence_rule_id?'↻ ':'')+esc(t.title)+'<small>'+esc(pname(t.project_id))+'</small>'}
function ev(t,st=null){let s=st!=null?st:tm(t.start_time),d=dur(t);return{task:t,a:s,b:s+d,l:0,n:1,auto:st!=null}}function ov(a,b){return a.a<b.b&&b.a<a.b}
function lane(es){es=es.slice().sort((a,b)=>a.a-b.a||a.b-b.b);let lanes=[];es.forEach(e=>{let i=lanes.findIndex(x=>x<=e.a);if(i<0){i=lanes.length;lanes.push(e.b)}else lanes[i]=e.b;e.l=i;e.n=Math.max(1,lanes.length)});es.forEach(e=>e.n=Math.max(e.n,lanes.length));return es}
function place(ut,td){let ds=TL0*60,de=TL1*60,pl=[],uo=[];for(let t of ut){let slot=null;for(let m=ds;m+TLD<=de;m+=TLS){let c={a:m,b:m+TLD};if(!td.some(x=>ov({a:x.a,b:x.b},c))&&!pl.some(x=>ov({a:x.a,b:x.b},c))){slot=m;break}}slot==null?uo.push(t):pl.push(ev(t,slot))}pl.forEach(x=>x.auto=true);return{pl,uo}}
function est(e){let ds=TL0*60,de=TL1*60,a=Math.max(ds,e.a),b=Math.min(de,e.b),top=(a-ds)*TLP,h=Math.max(24,(b-a)*TLP);return'--top:'+top+'px;--height:'+h+'px;--lane:'+(e.l||0)+';--lanes:'+(e.n||1)+';--accent:'+pcolor(e.task.project_id)+';--bg:'+rgba(pcolor(e.task.project_id),.18)}
function cardE(e){let t=e.task;return'<div class="timeline-event timed '+(e.auto?'untimed-auto ':'')+(t.status==='done'?'done ':'')+'" style="'+est(e)+'" data-action="tl-open" data-id="'+t.id+'"><div>'+tt(t)+'</div>'+(e.auto?'<em>без времени</em>':'')+'</div>'}
function renderCalendarTimeline(){S.timelineDate=S.timelineDate||today();let ws=wstart(S.timelineDate),days=Array.from({length:7},(_,i)=>add(ws,i)),f=tf(),tasks=S.tasks.filter(t=>passT(t,f)),gh=(TL1-TL0)*60*TLP,hrs=[];for(let h=TL0;h<=TL1;h++)hrs.push(h);let po='<option value="all">Все проекты</option>'+S.projects.map(p=>'<option value="'+p.id+'" '+(f.p===p.id?'selected':'')+'>'+esc(p.name)+'</option>').join(''),uo='<option value="all">Все исполнители</option>'+S.users.map(u=>'<option value="'+u.id+'" '+(f.u===u.id?'selected':'')+'>'+esc(u.display_name||u.email)+'</option>').join('');let html='<div class="timeline-calendar"><div class="timeline-calendar-toolbar"><button class="btn sm secondary" data-action="tl-prev">←</button><button class="btn sm secondary" data-action="tl-next">→</button><button class="btn sm secondary" data-action="tl-today">Сегодня</button><b>'+fmt(days[0])+'–'+fmt(days[6])+'</b><input class="input" id="tlQ" placeholder="Поиск" value="'+esc(f.q)+'"><select class="input" id="tlP">'+po+'</select><select class="input" id="tlU">'+uo+'</select><select class="input" id="tlS"><option value="all">Все статусы</option>'+Object.entries(ST).map(([k,v])=>'<option value="'+k+'" '+(f.s===k?'selected':'')+'>'+esc(v)+'</option>').join('')+'</select><select class="input" id="tlR"><option value="all">Все приоритеты</option>'+Object.entries(PR).map(([k,v])=>'<option value="'+k+'" '+(f.r===k?'selected':'')+'>'+esc(v)+'</option>').join('')+'</select><label class="tl-check"><input type="checkbox" id="tlDone" '+(f.done?'checked':'')+'> Выполненные</label></div><div class="timeline-calendar-grid" style="--grid-height:'+gh+'px"><div class="timeline-time-head"></div>'+days.map(d=>'<div class="timeline-calendar-day-head '+(d===today()?'today':'')+'"><b>'+D(d).toLocaleDateString('ru-RU',{weekday:'short',day:'2-digit',month:'2-digit'})+'</b><button class="week-add-task-btn" data-action="tl-add-day" data-date="'+d+'">+</button></div>').join('')+'<div class="timeline-time-col"><div class="timeline-all-day-label">Без времени</div>'+hrs.map(h=>'<div class="timeline-hour-label" style="top:'+((h-TL0)*60*TLP)+'px">'+pad(h)+':00</div>').join('')+'</div>';days.forEach(d=>{let dt=tasks.filter(t=>inDay(t,d)),timed=dt.filter(t=>t.start_time&&!t.is_all_day).map(t=>ev(t)),unt=dt.filter(t=>!t.start_time||t.is_all_day),u=place(unt,timed),all=lane([...timed,...u.pl]),now='';if(d===today()){let n=new Date(),m=n.getHours()*60+n.getMinutes(),ds=TL0*60,de=TL1*60;if(m>=ds&&m<=de)now='<div class="timeline-now-line" style="top:'+((m-ds)*TLP)+'px"></div>'}html+='<div class="timeline-day-col '+(d===today()?'today':'')+'"><div class="timeline-all-day-cell">'+u.uo.slice(0,6).map(t=>'<div class="timeline-event all-day" data-action="tl-open" data-id="'+t.id+'">'+esc(t.title)+' <em>без времени</em></div>').join('')+(u.uo.length>6?'<span class="muted">+'+(u.uo.length-6)+'</span>':'')+'</div><div class="timeline-time-grid" data-action="tl-empty" data-date="'+d+'">'+hrs.slice(0,-1).map(h=>'<div class="timeline-hour-line" style="top:'+((h-TL0)*60*TLP)+'px"></div><div class="timeline-half-hour-line" style="top:'+(((h-TL0)*60+30)*TLP)+'px"></div>').join('')+now+all.map(cardE).join('')+'</div></div>'});return html+'</div></div>'}
/* Calendar timeline v1 end */
'''
CSSB=r'''
/* Calendar timeline v1 start */
.task-calendar-box{border:1px solid #e5e7eb;border-radius:14px;padding:12px;background:#f8fafc;display:grid;gap:10px}.task-calendar-head{display:flex;align-items:center;gap:8px;font-weight:800}.task-calendar-time-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}.timeline-calendar{display:grid;gap:12px}.timeline-calendar-toolbar{display:grid;grid-template-columns:repeat(4,auto) minmax(160px,1fr) repeat(4,minmax(130px,1fr)) auto;gap:8px;align-items:center}.timeline-calendar-grid{display:grid;grid-template-columns:58px repeat(7,minmax(170px,1fr));border:1px solid #e5e7eb;border-radius:18px;overflow:auto;background:#fff}.timeline-time-head,.timeline-calendar-day-head{position:sticky;top:0;z-index:5;background:#fff;border-bottom:1px solid #e5e7eb;min-height:48px;display:flex;align-items:center;justify-content:center;gap:8px}.timeline-calendar-day-head.today{background:#eff6ff}.timeline-time-col{position:relative;border-right:1px solid #e5e7eb;min-height:calc(var(--grid-height) + 58px);background:#fbfdff}.timeline-all-day-label{height:58px;border-bottom:1px solid #e5e7eb;display:flex;align-items:center;justify-content:center;font-size:11px;color:#64748b;text-align:center}.timeline-hour-label{position:absolute;left:6px;transform:translateY(-8px);font-size:11px;color:#64748b}.timeline-day-col{position:relative;border-right:1px solid #eef2f7;min-height:calc(var(--grid-height) + 58px);min-width:170px;background:#fff}.timeline-day-col.today{background:linear-gradient(180deg,#eff6ff,#fff 90px)}.timeline-all-day-cell{height:58px;border-bottom:1px solid #e5e7eb;overflow:auto;padding:4px;display:flex;flex-wrap:wrap;gap:3px}.timeline-time-grid{position:relative;height:var(--grid-height);cursor:crosshair}.timeline-hour-line,.timeline-half-hour-line{position:absolute;left:0;right:0;border-top:1px solid #eef2f7;pointer-events:none}.timeline-half-hour-line{border-top-style:dashed;opacity:.55}.timeline-now-line{position:absolute;left:0;right:0;border-top:2px solid #ef4444;z-index:4}.timeline-event{border:1px solid color-mix(in srgb,var(--accent,#2563eb) 45%,#fff);background:var(--bg,#eff6ff);border-radius:8px;padding:5px 6px;font-size:11px;line-height:1.18;overflow:hidden;color:#0f172a;box-shadow:0 2px 7px rgba(15,23,42,.06);cursor:pointer}.timeline-event small{display:block;color:#475569;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.timeline-event.timed{position:absolute;top:var(--top);height:var(--height);left:calc(var(--lane) * (100% / var(--lanes)) + 3px);width:calc((100% / var(--lanes)) - 6px);z-index:3}.timeline-event.untimed-auto{border-style:dashed}.timeline-event.all-day{display:inline-flex;gap:3px;align-items:center;max-width:100%;padding:3px 6px}.timeline-event.done{text-decoration:line-through;opacity:.68}.timeline-event em{font-style:normal;color:#2563eb;font-weight:800;font-size:10px}.tl-check{font-size:12px;color:#475569;display:flex;gap:5px;align-items:center}.week-add-task-btn{width:22px;height:22px;border:1px solid #dbe4ef;border-radius:999px;background:#fff;color:#2563eb;font-weight:900;cursor:pointer}@media(max-width:720px){.task-calendar-time-grid{grid-template-columns:1fr}.timeline-calendar-grid{grid-template-columns:52px repeat(7,220px)}.timeline-calendar-toolbar{grid-template-columns:repeat(3,auto) 1fr}.timeline-calendar-toolbar select,.timeline-calendar-toolbar input,.timeline-calendar-toolbar label{grid-column:1/-1}}
/* Calendar timeline v1 end */
'''
