def rf(src,name,repl):
 i=src.find('function '+name); b=src.find('{',i); d=0; q=None; esc=False; j=b
 if i<0 or b<0: raise SystemExit(name+' not found')
 while j<len(src):
  ch=src[j]
  if q:
   if esc: esc=False
   elif ch=='\\': esc=True
   elif ch==q: q=None
  else:
   if ch in "'\"`": q=ch
   elif ch=='{': d+=1
   elif ch=='}':
    d-=1
    if d==0: return src[:i]+repl+src[j+1:]
  j+=1
 raise SystemExit(name+' end not found')

