s=rf(s,'renderTimeline',"function renderTimeline(){let e=$('timeline');if(!e)return;e.innerHTML=renderCalendarTimeline();selectsMaybe()}")
s=s.replace("$('taskNotes').value=t?.notes||'';","$('taskNotes').value=t?.notes||'';fillTaskCalendarFields(t);",1).replace('fillTaskCalendarFields(t);fillTaskCalendarFields(t);','fillTaskCalendarFields(t);')
m=re.search(r"async function saveTask\(e\)\{[\s\S]*?\}\nasync function saveUser",s)
if not m: raise SystemExit('saveTask not found')
sv="async function saveTask(e){e.preventDefault();ensureTaskCalendarUi();let id=$('taskId').value||null,row={title:$('taskTitle').value.trim(),project_id:$('taskProject').value,status:$('taskStatus').value,priority:$('taskPriority').value,start_date:$('taskStart').value||null,due_date:$('taskDue').value||null,notes:$('taskNotes').value||null};if(!row.title)return alert('Введите название задачи');try{Object.assign(row,readTaskCalendarFields())}catch(err){alert(err.message||String(err));return}let selected=qa('#taskAssignee option').filter(o=>o.selected).map(o=>o.value);row.assignee_id=selected[0]||null;if(!id&&typeof taskRecurrenceEnabled==='function'&&taskRecurrenceEnabled()){try{await createRecurringTasks(row,selected);$('taskModal').close();await load();return}catch(err){alert(err.message||String(err));return}}let r=id?await S.sb.from('tasks').update(row).eq('id',id).select().single():await S.sb.from('tasks').insert(row).select().single();if(r.error)throw Error(r.error.message);let taskId=r.data.id;await S.sb.from('task_assignees').delete().eq('task_id',taskId).then(()=>0);if(selected.length)await S.sb.from('task_assignees').insert(selected.map(user_id=>({task_id:taskId,user_id}))).then(()=>0);$('taskModal').close();await load()}\nasync function saveUser"
s=s[:m.start()]+sv+s[m.end():]
s=s.replace('is_favorite:false,recurrence_rule_id:ruleId,recurrence_date:d','is_favorite:false,start_time:baseRow.start_time||null,end_time:baseRow.end_time||null,duration_minutes:baseRow.duration_minutes||null,is_all_day:!!baseRow.is_all_day,recurrence_rule_id:ruleId,recurrence_date:d')
H="""
/* Calendar timeline handlers v1 start */
document.addEventListener('change',e=>{if(e.target&&e.target.id==='taskAllDay')syncTaskCalendarUi();if(e.target&&['tlP','tlU','tlS','tlR','tlDone'].includes(e.target.id)&&S.view==='timeline')renderTimeline()},true);document.addEventListener('input',e=>{if(e.target&&e.target.id==='tlQ'&&S.view==='timeline')renderTimeline()},true);document.addEventListener('click',e=>{let b=e.target.closest?.('[data-action]');if(!b)return;let a=b.dataset.action;if(!String(a).startsWith('tl-'))return;if(a==='tl-prev'){S.timelineDate=add(S.timelineDate||today(),-7);renderTimeline();return}if(a==='tl-next'){S.timelineDate=add(S.timelineDate||today(),7);renderTimeline();return}if(a==='tl-today'){S.timelineDate=today();renderTimeline();return}if(a==='tl-open'){e.preventDefault();e.stopPropagation();openTask(b.dataset.id);return}if(a==='tl-add-day'){e.preventDefault();e.stopPropagation();openTask(null);let d=b.dataset.date;if($('taskStart'))$('taskStart').value=d;if($('taskDue'))$('taskDue').value=d;fillTaskCalendarFields({});return}if(a==='tl-empty'){if(e.target.closest('.timeline-event'))return;let c=e.target.closest('.timeline-time-grid');if(!c)return;let r=c.getBoundingClientRect(),y=e.clientY-r.top,m=TL0*60+Math.round((y/TLP)/TLS)*TLS,tm=mt(m),en=mt(m+TLD),d=c.dataset.date;openTask(null);if($('taskStart'))$('taskStart').value=d;if($('taskDue'))$('taskDue').value=d;fillTaskCalendarFields({start_time:tm,end_time:en,duration_minutes:TLD,is_all_day:false});return}},true);
/* Calendar timeline handlers v1 end */
"""
