html=re.sub(r"assets/app\.js\?v=[^'\"]+",'assets/app.js?v='+VER,html);html=re.sub(r"assets/app\.css\?v=[^'\"]+",'assets/app.css?v='+VER,html);I.write_text(html,encoding='utf-8')
